// // This D flip-flop loads data on the falling edge of the clock and holds the value on the rising edge.
module top_module( clk, ld, d, q );input clk; 
  input ld; 
  input [63:0] d; 
  output [63:0] q; 
  reg [63:0] q; 
 `ifdef RANDOM_INIT 
  initial 
  $random_init("q"); 
 `endif 
  always @(posedge clk) begin 
  if (ld) 
  q <= d; 
  end 
 endmodule
